const groupAnagrams = (words) => {
  const anagramMap = new Map();
  const order = [];

  for (const word of words) {
    // Create a canonical key for the word by sorting its characters
    const sortedKey = word.split('').sort().join('');

    if (!anagramMap.has(sortedKey)) {
      anagramMap.set(sortedKey, []);
      // Record the order of appearance of this group's first member
      order.push(sortedKey);
    }

    // Add the word to the corresponding group
    anagramMap.get(sortedKey).push(word);
  }

  // Construct the result array following the order of first appearance
  const result = [];
  for (const key of order) {
    result.push(anagramMap.get(key));
  }

  return result;
};
