const lengthOfLongestSubstring = (s) => {
    let maxLength = 0;
    let start = 0;
    const charIndexMap = new Map();

    for (let end = 0; end < s.length; end++) {
        const char = s[end];

        if (charIndexMap.has(char) && charIndexMap.get(char) >= start) {
            // If the character is found within the current window [start, end-1],
            // move the start pointer to the position right after the last occurrence of this character.
            start = charIndexMap.get(char) + 1;
        }

        // Update the index of the current character
        charIndexMap.set(char, end);

        // Calculate the current window length and update maxLength
