/**
 * @param {number[]} coins
 * @param {number} amount
 * @return {number}
 */
const coinChange = (coins, amount) => {
    if (amount === 0) {
        return 0;
    }

    // dp[i] will store the minimum number of coins needed to make amount i
    // Initialize with amount + 1, which is effectively infinity for this problem,
    // since the maximum number of coins needed would be 'amount' (if all coins were 1).
    const dp = new Array(amount + 1).fill(amount + 1);

    // Base case: 0 coins needed for amount 0
    dp[0] = 0;

    // Iterate through all amounts from 1 up to the target amount
    for (let i = 1; i <= amount; i++) {
        // For each amount i, check every available coin
        for (const coin of coins) {
            // If the current coin can be used to form amount i
            if (coin <= i) {
                // Update dp[i] with the minimum of its current value
                // or 1 + the minimum coins needed for the remaining amount (i - coin)
                dp[i] = Math.min(dp[i], 1 + dp[i - coin]);
            }
        }
    }

    // If dp[amount] is still amount + 1, it means the amount cannot be formed
    return dp[amount] > amount ? -1 : dp[amount];
};
