/**
 * Rounds a number to the nearest integer with halves rounded up (towards +Infinity).
 * @param {number} x The number to round.
 * @returns {number} The rounded integer.
 */
const roundHalfUp = (x) => {
  // The standard JavaScript Math.round() rounds halves to the nearest even integer
  // (e.g., Math.round(2.5) is 3, Math.round(3.5) is 4, but Math.round(2.5) in some
  // contexts or implementations might be expected to follow different rules,
  // although modern JS typically rounds .5 away from zero or to the nearest even.
  // The requirement is: ties (exactly .5) always going UP toward +Infinity.
  // 2.5 -> 3
  // -2.5 -> -2 (since -2 is greater than -3)

  // Adding 0.5 and then flooring implements "round half up" for positive numbers.
  // Math.floor(x + 0.5)
  // 2.5 + 0.5 = 3.0 -> floor(3.0) = 3
  // 2.4 + 0.5 = 2.9 -> floor(2.9) = 2

  // For negative numbers, we need to be careful.
  // -2.5. Adding 0.5 gives -2.0. floor(-2.0) = -2. (Correct, -2 is up from -3)
  // -2.6. Adding 0.5 gives -2.1. floor(-2.1) = -3. (Correct)
  // -2.4. Adding 0.5 gives -1.9. floor(-1.9) = -2. (Correct)

  // This approach (floor(x + 0.5)) correctly implements rounding half up towards +Infinity.
  return Math.floor(x + 0.5);
};
