class Game2048 {
    constructor(board, spawnQueue) {
        this.board = this._copyBoard(board);
        this.spawnQueue = [...spawnQueue];
        this.score = 0;
    }

    _copyBoard(board) {
        return board.map(row => [...row]);
    }

    getBoard() {
        return this.board;
    }

    getScore() {
        return this.score;
    }

    isGameOver() {
        let hasEmpty = false;
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                if (this.board[r][c] === 0) {
                    hasEmpty = true;
                    break;
                }
            }
            if (hasEmpty) break;
        }

        if (hasEmpty) return false;

        // Check for adjacent equal tiles
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                const val = this.board[r][c];
                if (val === 0) continue;

                // Check right
                if (c + 1 < 4 && this.board[r][c + 1] === val) return false;
                // Check down
                if (r + 1 < 4 && this.board[r + 1][c] === val) return false;
            }
        }

        return true;
    }

    _compress(line) {
        const filtered = line.filter(val => val !== 0);
        const newLine = [...filtered, ...Array(4 - filtered.length).fill(0)];
        return newLine;
    }

    _merge(line) {
        const merged = [];
        let i = 0;
        let changed = false;
        while (i < 4) {
            const current = line[i];
            if (current !== 0) {
                if (i + 1 < 4 && line[i + 1] !== 0 && current === line[i + 1]) {
                    const mergedValue = current * 2;
                    merged.push(mergedValue);
                    this.score += mergedValue;
                    i += 2; // Skip the next tile as it was merged
                    changed = true;
                } else {
                    merged.push(current);
                    i += 1;
                }
            } else {
                merged.push(0);
                i += 1;
            }
        }

        // Pad the rest with zeros
        while (merged.length < 4) {
            merged.push(0);
        }

        // Re-compress in case merging didn't fill the line (e.g., [2, 2, 0, 0] -> [4, 0, 0, 0])
        const compressedLine = this._compress(merged);

        return { newLine: compressedLine, changed: changed };
    }

    _processLine(line, direction) {
        let lineChanged = false;

        if (direction === "left" || direction === "up") {
            // Compression and Merging happens left-to-right or top-to-bottom
            const compressed = this._compress(line);
            const { newLine: mergedLine, changed: mergeHappened } = this._merge(compressed);

            // Check if any change occurred (compression or merge)
            let originalHasZeros = line.includes(0);
            let newHasZeros = mergedLine.includes(0);

            lineChanged = originalHasZeros !== newHasZeros || mergeHappened;

            return { newLine: mergedLine, changed: lineChanged };
        } else { // "right" or "down"
            // Reverse, process as 'left', then reverse back
            const reversedLine = [...line].reverse();
            const { newLine: mergedReversed, changed: mergeHappened } = this._merge(reversedLine);
            const finalLine = mergedReversed.reverse();

            // Check if any change occurred
            let originalHasZeros = line.includes(0);
            let newHasZeros = finalLine.includes(0);

            let lineChanged = originalHasZeros !== newHasZeros || mergeHappened;

            return { newLine: finalLine, changed: lineChanged };
        }
    }


    move(dir) {
        let boardChanged = false;
        const originalBoard = this._copyBoard(this.board);
        const newBoard = this._copyBoard(this.board);

        if (dir === "left" || dir === "right") {
            for (let r = 0; r < 4; r++) {
                const row = this.board[r];
                const { newLine: processedRow, changed: lineChanged } = this._processLine(row, dir);

                if (lineChanged) {
                    boardChanged = true;
                    newBoard[r] = processedRow;
                }
            }
        } else { // "up" or "down"
            for (let c = 0; c < 4; c++) {
                // Extract column
                const col = [];
                for (let r = 0; r < 4; r++) {
                    col.push(this.board[r][c]);
                }

                // Process column (treating it as a line)
                const { newLine: processedCol, changed: lineChanged } = this._processLine(col, dir);

                if (lineChanged) {
                    boardChanged = true;
                    // Place processed column back
                    for (let r = 0; r < 4; r++) {
                        newBoard[r][c] = processedCol[r];
                    }
                }
            }
        }

        if (boardChanged) {
            this.board = newBoard;

            // Consume spawn
            if (this.spawnQueue.length > 0) {
                const spawn = this.spawnQueue.shift();
                const { r, c, v } = spawn;

                // Spawn must go into an empty cell (guaranteed by game rules if move was possible)
                if (this.board[r][c] === 0) {
                    this.board[r][c] = v;
                }
            }
            return true;
        } else {
            // No change, no spawn consumed
            return false;
        }
    }
}
