const reverseWords = (s) => {
    // 1. Trim leading/trailing whitespace.
    // 2. Split the string by one or more whitespace characters (\s+).
    // 3. Filter out any resulting empty strings (which can happen if the input was empty or only whitespace).
    const words = s.trim().split(/\s+/).filter(word => word.length > 0);

    // 4. Reverse the order of the words.
    const reversedWords = words.reverse();

    // 5. Join the words back into a single string, separated by exactly one space.
    return reversedWords.join(' ');
