        const [nextStart, nextEnd] = nextInterval;

        // Check for overlap or touching: next interval starts before or exactly when current ends
        if (nextStart <= currentEnd) {
            // Merge: update the end of the current interval to the maximum end time
            currentInterval[1] = Math.max(currentEnd, nextEnd);
        } else {
            // No overlap, finalize the current interval and start a new one
            merged.push(currentInterval);
            currentInterval = nextInterval;
        }
    }

    // Add the last processed interval
    merged.push(currentInterval);

    return merged;
