        for (let c = left; c <= right; c++) {
            result.push(matrix[top][c]);
        }
        top++;

        // 2. Traverse Down (Right Column)
        for (let r = top; r <= bottom; r++) {
            result.push(matrix[r][right]);
        }
        right--;

        // Check boundary before traversing left/up, as boundaries might have crossed
        if (top <= bottom) {
            // 3. Traverse Left (Bottom Row)
            for (let c = right; c >= left; c--) {
                result.push(matrix[bottom][c]);
            }
            bottom--;
        }

        if (left <= right) {
            // 4. Traverse Up (Left Column)
            for (let r = bottom; r >= top; r--) {
                result.push(matrix[r][left]);
            }
            left++;
        }
    }

    return result;
