```javascript
class Game2048 {
    constructor(board, spawnQueue) {
        // Deep copy the board
        this.board = board.map(row => [...row]);
        this.score = 0;
        this.spawnQueue = [...spawnQueue];
        this.BOARD_SIZE = 4;
    }

    /**
     * Processes a single line (row or column) for sliding and merging.
     * This internal method always assumes movement starts from index 0 (left/top)
     * and returns the processed line and score gained.
     * 
     * @param {number[]} line - The array line (4 elements).
     * @returns {[number[], number]} [newLine, scoreGained]
     */
    _processLine(line) {
        let scoreGained = 0;
        let compacted = line.filter(x => x !== 0);
        let newLine = new Array(this.BOARD_SIZE).fill(0);
        let writePointer = 0;
        let mergedFlags = new Array(compacted.length).fill(false);

        // Merging loop
        for (let i = 0; i < compacted.length; i++) {
            if (mergedFlags[i]) continue;

            // Check for merge with the next tile
            if (i + 1 < compacted.length && compacted[i] === compacted[i + 1] && !mergedFlags[i + 1]) {
                let mergedValue = compacted[i] * 2;
                scoreGained += mergedValue;

                newLine[writePointer++] = mergedValue;

                // Mark both tiles as used/merged
                mergedFlags[i] = true;
                mergedFlags[i + 1] = true;
            } else {
                // No merge, copy the tile
                newLine[writePointer++] = compacted[i];
            }
        }

        // Padding with zeros is handled by initializing newLine to zeros.
        return [newLine, scoreGained];
    }

    /**
     * Transposes the 4x4 board (rows become columns and vice versa).
     * @param {number[][]} board 
     * @returns {number[][]}
     */
    _transpose(board) {
        const newBoard = Array.from({ length: 4 }, () => new Array(4).fill(0));
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                newBoard[c][r] = board[r][c];
            }
        }
        return newBoard;
    }

    /**
     * Reverses a line array.
     * @param {number[]} line 
     * @returns {number[]}
     */
    _reverseLine(line) {
        return [...line].reverse();
    }

    getBoard() {
        return this.board.map(row => [...row]); // Return a copy
    }

    getScore() {
        return this.score;
    }

    /**
     * Checks if the game is over: no empty cells AND no possible merges.
     * @returns {boolean}
     */
    isGameOver() {
        // 1. Check for empty cells
        const hasEmpty = this.board.flat().some(val => val === 0);
        if (hasEmpty) return false;

        // 2. Check for adjacent equal tiles (potential move)
        // Check rows
        for (let r = 0; r < this.BOARD_SIZE; r++) {
            for (let c = 0; c < this.BOARD_SIZE - 1; c++) {
                if (this.board[r][c] === this.board[r][c + 1]) {
                    return false; // Horizontal merge possible
                }
            }
        }

        // Check columns
        for (let c = 0; c < this.BOARD_SIZE; c++) {
            for (let r = 0; r < this.BOARD_SIZE - 1; r++) {
                if (this.board[r][c] === this.board[r + 1][c]) {
                    return false; // Vertical merge possible
                }
            }
        }

        // If no empty cells and no adjacent equal tiles, game is over
        return true;
    }

    move(dir) {
        let originalBoard = this.board.map(row => [...row]);
        let scoreDelta = 0;
        let newBoard = JSON.parse(JSON.stringify(this.board));
        let boardChanged = false;

        // Determine if we are processing horizontal (rows) or vertical (columns) lines
        const isHorizontal = (dir === "left" || dir === "right");

        if (isHorizontal) {
            // --- Horizontal Movement (Rows) ---
            for (let r = 0; r < this.BOARD_SIZE; r++) {
                let line = this.board[r];
                let processedLine;
                let lineScore;

                if (dir === "left") {
                    [processedLine, lineScore] = this._processLine(line);
                } else { // "right"
                    // Reverse line, process left-to-right, then reverse result
                    let reversedLine = this._reverseLine(line);
                    let [processedReversed, score] = this._processLine(reversedLine);

                    processedLine = this._reverseLine(processedReversed);
                    lineScore = score;
                }

                scoreDelta += lineScore;
                newBoard[r] = processedLine;
            }
        } else {
            // --- Vertical Movement (Columns) ---
            // 1. Transpose to treat columns as rows
            const transposedBoard = this._transpose(this.board);
            let transposedNewBoard = transposedBoard.map(row => [...row]);

            for (let c = 0; c < this.BOARD_SIZE; c++) {
                let line = transposedBoard[c];
                let processedLine;
                let lineScore;

                if (dir === "up") {
                    // Process up (equivalent to left movement on transposed)
                    [processedLine, lineScore] = this._processLine(line);
                } else { // "down"
                    // Process down (equivalent to right movement on transposed)
                    let reversedLine = this._reverseLine(line);
                    let [processedReversed, score] = this._processLine(reversedLine);

                    processedLine = this._reverseLine(processedReversed);
                    lineScore = score;
                }

                scoreDelta += lineScore;
                transposedNewBoard[c] = processedLine;
            }

            // 2. Transpose back
            newBoard = this._transpose(transposedNewBoard);
        }

        // Check if the board state changed
        const originalString = JSON.stringify(originalBoard);
        const newString = JSON.stringify(newBoard);

        if (originalString !== newString) {
            this.board = newBoard;
            this.score += scoreDelta;
            boardChanged = true;
        }

        // Handle spawning if the board changed
        if (boardChanged && this.spawnQueue.length > 0) {
            const spawn = this.spawnQueue.shift();
            const { r, c, v } = spawn;

            // Set the new tile. The spec guarantees the spawn location is valid.
            this.board[r][c] = v;
        }

        return boardChanged;
    }
}
