const mergeIntervals = (intervals) => {
    if (!intervals || intervals.length === 0) {
        return [];
    }

    // Sort intervals based on the start time
    intervals.sort((a, b) => a[0] - b[0]);

    const merged = [];
    let currentInterval = intervals[0];

    for (let i = 1; i < intervals.length; i++) {
        const nextInterval = intervals[i];
        const currentEnd = currentInterval[1];
        const nextStart = nextInterval[0];

        // Check for overlap or touching: currentEnd >= nextStart
        // This handles both [1, 3] and [1, 2] touching [2, 3]
        if (currentEnd >= nextStart) {
            // Merge: update the end of the current interval to the maximum of the two ends
            currentInterval[1] = Math.max(currentEnd, nextInterval[1]);
        } else {
            // No overlap, push the current merged interval and start a new one
            merged.push(currentInterval);
            currentInterval = nextInterval;
        }
    }

    // Push the last processed interval
    merged.push(currentInterval);

    return merged;
