function coinChange(coins, amount) {
    if (amount === 0) {
        return 0;
    }

    // dp[i] will store the minimum number of coins needed to make amount i.
    const dp = new Array(amount + 1).fill(Infinity);

    // Base case: 0 coins needed for amount 0.
    dp[0] = 0;

    // Iterate through all possible amounts from 1 up to the target amount
    for (let i = 1; i <= amount; i++) {
        // Try every coin denomination
        for (const coin of coins) {
            // If the current coin can be used
            if (i >= coin) {
                // Update dp[i] if using this coin leads to a smaller count
                // We must ensure dp[i - coin] is not Infinity before adding 1
                if (dp[i - coin] !== Infinity) {
                    dp[i] = Math.min(dp[i], dp[i - coin] + 1);
                }
            }
        }
    }

    // If dp[amount] is Infinity, it means the amount cannot be formed.
    return dp[amount] === Infinity ? -1 : dp[amount];
}
