    const n = b.length;

    // Create a 2D array (m+1) x (n+1)
    const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

    // Initialize base cases
    for (let i = 0; i <= m; i++) {
        dp[i][0] = i;
    }
    for (let j = 0; j <= n; j++) {
        dp[0][j] = j;
