        if (dir === "right") {
            // Reverse back to original orientation
            return { newLine: newLine.reverse(), scoreChange: scoreChange };
        }
        return { newLine: newLine, scoreChange: scoreChange };
    }

    /**
     * Handles the movement logic.
     * @param {"left" | "right" | "up" | "down"} dir - The direction of movement.
     * @returns {boolean} - True if the board changed, false otherwise.
     */
    move(dir) {
        const oldBoard = this._deepCopyBoard();
        let totalScoreChange = 0;
        let boardChanged = false;

        // Determine the transformation strategy
        let currentBoard = this.board;

        // Transpose for Up/Down movement (rows become columns)
        if (dir === "up" || dir === "down") {
            // Transpose (rows -> columns)
            currentBoard = Array(4).fill(0).map((_, c) =>
                Array(4).fill(0).map((_, r) => this.board[r][c])
            );
            // Now, the "rows" of currentBoard are the original columns.
        }

        // Process movement based on row/column structure
        if (dir === "left" || dir === "right") {
            for (let r = 0; r < 4; r++) {
                const line = currentBoard[r];
                const { newLine, scoreChange } = this._processLine(line, dir);

                if (newLine.some((val, i) => val !== line[i])) {
                    boardChanged = true;
                    totalScoreChange += scoreChange;
                    currentBoard[r] = newLine;
                }
            }
        } else if (dir === "up" || dir === "down") {
            // Since we transposed, we process rows (which are the original columns)
            for (let r = 0; r < 4; r++) {
                const line = currentBoard[r];
                const { newLine, scoreChange } = this._processLine(line, dir);

                if (newLine.some((val, i) => val !== line[i])) {
                    boardChanged = true;
                    totalScoreChange += scoreChange;
                    currentBoard[r] = newLine;
                }
            }
        }

        // Transpose back if necessary
        if (dir === "up" || dir === "down") {
            const newBoard = Array(4).fill(0).map((_, r) =>
                Array(4).fill(0).map((_, c) => currentBoard[c][r])
            );
            this.board = newBoard;
        } else {
            this.board = currentBoard;
        }

        if (boardChanged) {
            // 1. Update score
            this.score += totalScoreChange;

            // 2. Apply spawn
            if (this.spawnIndex < this.spawnQueue.length) {
                const spawn = this.spawnQueue[this.spawnIndex];
                // Set the new tile value at the specified location
                this.board[spawn.r][spawn.c] = spawn.v;
                this.spawnIndex++;
            }
            return true;
        }
        return false;
    }

    /**
     * @returns {number[][]} The current 4x4 grid.
     */
    getBoard() {
        return this.board.map(row => [...row]); // Return a copy
    }

    /**
     * @returns {number} The running score.
     */
    getScore() {
        return this.score;
    }

    /**
     * @returns {boolean} True if the game is over.
     */
    isGameOver() {
        // Condition 1: Check for empty cells
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                if (this.board[r][c] === 0) {
                    return false;
                }
            }
        }

        // Condition 2: Check for adjacent equal tiles (no possible move)

        // Horizontal check
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 3; c++) {
                if (this.board[r][c] === this.board[r][c + 1]) {
                    return false;
                }
            }
        }

        // Vertical check
        for (let r = 0; r < 3; r++) {
            for (let c = 0; c < 4; c++) {
                if (this.board[r][c] === this.board[r + 1][c]) {
                    return false;
                }
            }
        }

        return true;
    }
